// Embedded brand asset served by the Worker so emails can reference a real
// hosted PNG (mail clients don't render SVG). Logo: JDM Connect gold lockup (@2x).
export const LOGO_GOLD_PNG_B64 = "";

// Decode the base64 PNG into bytes for an image/png Response.
export function logoPngBytes() {
  const bin = atob(LOGO_GOLD_PNG_B64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes;
}